// Replays flutter/test/goldens/fx_goldens.json, generated by executing the REAL
// RN lib/fxrates.js and lib/currencies.js. Cross rates, base-per-unit, rate
// rounding, response parsing, freshness, currency symbols, and both money
// formatters must match the live app to the digit.

import 'dart:convert';
import 'dart:io';

import 'package:flutter_test/flutter_test.dart';
import 'package:salapify/money/currencies.dart';
import 'package:salapify/money/fxrates.dart';

dynamic normalize(dynamic v) {
  if (v is num) return v.toDouble().isFinite ? v.toDouble() : null;
  if (v is Map) return v.map((k, x) => MapEntry(k.toString(), normalize(x)));
  if (v is List) return v.map(normalize).toList();
  return v;
}

void main() {
  final g = jsonDecode(File('test/goldens/fx_goldens.json').readAsStringSync())
      as Map<String, dynamic>;
  final rates = g['rates'] as Map<String, dynamic>;

  test('crossRate matches on every pair, gaps and junk included', () {
    for (final c in (g['cross'] as List).cast<Map<String, dynamic>>()) {
      expect(normalize(crossRate(rates, c['from'], c['to'])), normalize(c['r']),
          reason: '${c['from']}->${c['to']}');
    }
  });

  test('basePerUnit matches, missing and non-positive included', () {
    for (final c in (g['basePerUnit'] as List).cast<Map<String, dynamic>>()) {
      expect(normalize(basePerUnit(rates, c['code'])), normalize(c['r']),
          reason: '${c['code']}');
    }
  });

  test('roundRate matches JS toPrecision(4) on every case', () {
    for (final c in (g['roundRate'] as List).cast<Map<String, dynamic>>()) {
      expect(normalize(roundRate(c['in'])), normalize(c['out']),
          reason: '${c['in']}');
    }
  });

  test('parseRatesResponse matches, junk yields null', () {
    for (final c in (g['parse'] as List).cast<Map<String, dynamic>>()) {
      expect(normalize(parseRatesResponse(c['in'])), normalize(c['out']));
    }
  });

  test('isFresh matches on fresh, stale, and null', () {
    for (final c in (g['isFresh'] as List).cast<Map<String, dynamic>>()) {
      expect(isFresh(c['fetchedAt'], c['now'] as num), c['out'],
          reason: '${c['fetchedAt']}');
    }
  });

  test('currencySymbol matches, unknown and blank fall back', () {
    for (final c in (g['symbol'] as List).cast<Map<String, dynamic>>()) {
      expect(currencySymbol(c['code']), c['out'], reason: '${c['code']}');
    }
  });

  test('formatConverted matches, zero-decimal and grouping included', () {
    for (final c in (g['formatConverted'] as List).cast<Map<String, dynamic>>()) {
      final amount = c['amount'] == 'NaN' ? double.nan : c['amount'];
      expect(formatConverted(amount, c['code'] as String), c['out'],
          reason: '${c['amount']} ${c['code']}');
    }
  });

  test('formatForeign matches, rounds to whole', () {
    for (final c in (g['formatForeign'] as List).cast<Map<String, dynamic>>()) {
      final amount = c['amount'] == 'NaN' ? double.nan : c['amount'];
      expect(formatForeign(amount, c['code'] as String), c['out'],
          reason: '${c['amount']} ${c['code']}');
    }
  });

  test('convertAmount multiplies, or is null with no rate', () {
    expect(convertAmount(1000, 0.0176), closeTo(17.6, 1e-9));
    expect(convertAmount(0, 0.0176), 0);
    expect(convertAmount(1000, null), isNull);
  });

  test('the currency list and constants match the RN app', () {
    final want = (g['currencies'] as List).cast<Map<String, dynamic>>();
    expect(currencies.length, want.length);
    for (var i = 0; i < want.length; i++) {
      expect(currencies[i]['code'], want[i]['code']);
      expect(currencies[i]['symbol'], want[i]['symbol']);
    }
    expect(fxMaxAgeMs, g['maxAgeMs']);
    expect(fxEndpoint('PHP'), g['endpointPHP']);
  });
}
